import { useState } from "react";

// ============================================================
// DESIGN TOKENS — v4: Green ground + Yellow brand + Hero Image
// ============================================================
const tokens = {
  colors: {
    brand: {
      50:  "#FFFBE0",
      100: "#FFF3A3",
      300: "#FFE866",
      400: "#FFDD44",
      600: "#D4B000",
      800: "#8A7000",
      900: "#4A3C00",
    },
    green: {
      50:  "#EAF5EC",
      100: "#C2DFC8",
      300: "#6FAF80",
      500: "#3D7A52",
      600: "#2F6140",
      700: "#1F4A2E",
      800: "#153620",
      900: "#0C2215",
    },
    accent: { coral: "#FF6B4A" },
    semantic: { success: "#FFDD44", warning: "#FF6B4A", error: "#E63946", info: "#7EC8E3" },
  },
  typography: {
    display: { family: "'Bebas Neue', sans-serif", weight: "400", size: "clamp(64px, 12vw, 160px)", letterSpacing: "0.01em", lineHeight: "0.92" },
    heading:  { family: "'Barlow Condensed', sans-serif", weight: "700", letterSpacing: "0.02em" },
    serif:    { family: "'EB Garamond', serif", weight: "400", size: "18px", lineHeight: "1.55" },
    body:     { family: "'DM Sans', sans-serif", weight: "400", size: "16px", lineHeight: "1.65" },
    label:    { family: "'Barlow Condensed', sans-serif", weight: "600", size: "13px", letterSpacing: "0.12em" },
  },
  spacing: { xs: "4px", sm: "8px", md: "16px", lg: "32px", xl: "64px", "2xl": "128px" },
  radius:  { sm: "2px", md: "4px", lg: "8px", full: "9999px" },
  motion: { fast: "120ms", base: "200ms", easing: "cubic-bezier(0.4,0,0.2,1)" },
  // NEW: Hero image overlay tokens
  hero: {
    overlayColor: "#0C2215",   // green[900] tint base
    overlayOpacity: 0.72,      // default overlay strength
    overlayBlend: "multiply",  // CSS mix-blend-mode for the overlay
  },
};

const T = tokens;
const C = tokens.colors;

// Solid shadow lift hook
const useLift = (shadowColor, dist = 6) => {
  const [hov, setHov] = useState(false);
  return {
    hov,
    lifted: hov
      ? { transform: `translate(-${dist}px, -${dist}px)`, boxShadow: `${dist}px ${dist}px 0px ${shadowColor}` }
      : { transform: "translate(0,0)", boxShadow: "none" },
    bind: { onMouseEnter: () => setHov(true), onMouseLeave: () => setHov(false) },
  };
};

// ============================================================
// COMPONENTS
// ============================================================

const Btn = ({ variant = "primary", size = "md", children, onClick }) => {
  const liftColor = variant === "primary" ? C.brand[900] : C.brand[400];
  const { hov, lifted, bind } = useLift(liftColor, 5);
  const pad = size === "sm" ? "8px 16px" : size === "lg" ? "18px 40px" : "12px 28px";
  const fs  = size === "sm" ? "12px" : size === "lg" ? "16px" : "13px";
  const trans = `transform ${T.motion.base} ${T.motion.easing}, box-shadow ${T.motion.base} ${T.motion.easing}, background 120ms, color 120ms, border-color 120ms`;

  const styles = {
    primary:   { background: hov ? C.green[900] : C.brand[400], color: hov ? C.brand[400] : C.green[900],  borderColor: C.brand[400] },
    secondary: { background: "transparent", color: hov ? C.brand[400] : C.green[50], borderColor: hov ? C.brand[400] : C.green[300] },
    ghost:     { background: "transparent", color: hov ? C.brand[400] : C.green[300], borderColor: "transparent", textDecoration: hov ? "underline" : "none" },
  };

  return (
    <button {...bind} onClick={onClick} style={{
      fontFamily: T.typography.label.family, fontSize: fs, letterSpacing: "0.12em",
      fontWeight: 700, padding: pad, border: "2px solid", cursor: "pointer",
      textTransform: "uppercase", display: "inline-block", transition: trans,
      ...(variant !== "ghost" ? lifted : {}),
      ...styles[variant],
    }}>
      {children}
    </button>
  );
};

const Badge = ({ children, color = C.brand[400] }) => {
  const { lifted, bind } = useLift(color, 4);
  return (
    <span {...bind} style={{
      fontFamily: T.typography.label.family, fontSize: "11px", letterSpacing: "0.14em",
      fontWeight: 700, textTransform: "uppercase", padding: "4px 10px",
      background: "transparent", border: `1.5px solid ${color}`, color,
      borderRadius: T.radius.sm, display: "inline-block", cursor: "default",
      transition: `transform ${T.motion.base} ${T.motion.easing}, box-shadow ${T.motion.base} ${T.motion.easing}`,
      ...lifted,
    }}>
      {children}
    </span>
  );
};

const NavLink = ({ children }) => {
  const [hov, setHov] = useState(false);
  return (
    <span onMouseEnter={() => setHov(true)} onMouseLeave={() => setHov(false)} style={{
      fontFamily: T.typography.label.family, fontSize: "13px", letterSpacing: "0.1em",
      textTransform: "uppercase", color: hov ? C.brand[400] : C.green[100],
      cursor: "pointer", transition: "color 150ms ease",
      borderBottom: hov ? `1.5px solid ${C.brand[400]}` : "1.5px solid transparent", paddingBottom: "2px",
    }}>
      {children}
    </span>
  );
};

const ProjectCard = ({ label, accent, flex = 1 }) => {
  const { hov, lifted, bind } = useLift(accent ? C.brand[400] : C.green[300], 8);
  return (
    <div {...bind} style={{
      flex,
      background: accent ? C.green[600] : C.green[800],
      border: `1px solid ${hov ? (accent ? C.brand[400] : C.green[300]) : (accent ? C.green[500] : C.green[700])}`,
      display: "flex", alignItems: "flex-end", padding: "20px", cursor: "pointer",
      transition: `transform ${T.motion.base} ${T.motion.easing}, box-shadow ${T.motion.base} ${T.motion.easing}, border-color 120ms`,
      ...lifted,
    }}>
      <span style={{ fontFamily: T.typography.label.family, fontSize: "11px", letterSpacing: "0.16em", color: accent ? C.brand[400] : C.green[300], textTransform: "uppercase" }}>{label}</span>
    </div>
  );
};

const ValueCard = ({ label, body }) => {
  const { hov, lifted, bind } = useLift(C.brand[400], 6);
  return (
    <div {...bind} style={{
      background: C.green[700], padding: "40px 36px", cursor: "default",
      border: `1px solid ${hov ? C.brand[400] : "transparent"}`,
      transition: `transform ${T.motion.base} ${T.motion.easing}, box-shadow ${T.motion.base} ${T.motion.easing}, border-color 120ms`,
      ...lifted,
    }}>
      <div style={{ width: "32px", height: "2px", background: C.brand[400], marginBottom: "24px" }} />
      <h3 style={{ fontFamily: T.typography.heading.family, fontWeight: 700, fontSize: "22px", letterSpacing: "0.04em", textTransform: "uppercase", marginBottom: "16px", color: C.green[50] }}>{label}</h3>
      <p style={{ fontFamily: T.typography.body.family, fontSize: "15px", color: C.green[100], lineHeight: "1.7" }}>{body}</p>
    </div>
  );
};

const Swatch = ({ hex, ring }) => {
  const { lifted, bind } = useLift(C.brand[400], 3);
  return (
    <div {...bind} style={{ cursor: "default", transition: `transform ${T.motion.base} ${T.motion.easing}, box-shadow ${T.motion.base} ${T.motion.easing}`, ...lifted }}>
      <div style={{ width: "44px", height: "44px", background: hex, border: ring ? `2px solid ${C.green[50]}` : "none" }} />
      <div style={{ fontFamily: T.typography.label.family, fontSize: "9px", color: C.green[300], marginTop: "4px" }}>{hex}</div>
    </div>
  );
};

// ============================================================
// HERO IMAGE CONFIGURATOR — shown in design panel
// ============================================================
const HeroConfigurator = ({ config, onChange }) => {
  const [urlInput, setUrlInput] = useState("");

  const presetImages = [
    { label: "None",    url: "" },
    { label: "Forest",  url: "https://images.unsplash.com/photo-1448375240586-882707db888b?w=1600&q=80" },
    { label: "Studio",  url: "https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=1600&q=80" },
    { label: "City",    url: "https://images.unsplash.com/photo-1477959858617-67f85cf4f1df?w=1600&q=80" },
    { label: "Texture", url: "https://images.unsplash.com/photo-1557683316-973673baf926?w=1600&q=80" },
  ];

  return (
    <div>
      <div style={{ fontFamily: T.typography.label.family, fontSize: "11px", letterSpacing: "0.15em", color: C.green[500], marginBottom: "16px", textTransform: "uppercase" }}>
        Hero Background Image
      </div>

      {/* Quick presets */}
      <div style={{ display: "flex", gap: "8px", flexWrap: "wrap", marginBottom: "16px" }}>
        {presetImages.map(({ label, url }) => {
          const active = config.imageUrl === url;
          return (
            <button
              key={label}
              onClick={() => { onChange({ ...config, imageUrl: url }); setUrlInput(url); }}
              style={{
                fontFamily: T.typography.label.family, fontSize: "11px", letterSpacing: "0.1em",
                textTransform: "uppercase", padding: "6px 14px", cursor: "pointer",
                background: active ? C.brand[400] : "transparent",
                color: active ? C.green[900] : C.green[300],
                border: `1.5px solid ${active ? C.brand[400] : C.green[600]}`,
                transition: "all 150ms ease",
              }}
            >
              {url && (
                <span style={{
                  display: "inline-block", width: "20px", height: "14px",
                  backgroundImage: `url(${url})`, backgroundSize: "cover",
                  marginRight: "6px", verticalAlign: "middle", border: "1px solid rgba(255,255,255,0.2)"
                }} />
              )}
              {label}
            </button>
          );
        })}
      </div>

      {/* Custom URL input */}
      <div style={{ display: "flex", gap: "8px", marginBottom: "16px" }}>
        <input
          value={urlInput}
          onChange={e => setUrlInput(e.target.value)}
          placeholder="Paste image URL…"
          style={{
            flex: 1, background: C.green[800], border: `1px solid ${C.green[600]}`,
            color: C.green[50], fontFamily: T.typography.body.family, fontSize: "13px",
            padding: "8px 12px", outline: "none",
          }}
        />
        <Btn variant="primary" size="sm" onClick={() => onChange({ ...config, imageUrl: urlInput })}>
          Apply
        </Btn>
      </div>

      {/* Overlay controls — only visible when an image is set */}
      {config.imageUrl && (
        <div style={{ display: "flex", gap: "32px", alignItems: "flex-start", paddingTop: "12px", borderTop: `1px solid ${C.green[700]}` }}>
          {/* Opacity slider */}
          <div style={{ flex: 1 }}>
            <div style={{ fontFamily: T.typography.label.family, fontSize: "10px", color: C.green[400], letterSpacing: "0.1em", marginBottom: "8px" }}>
              OVERLAY OPACITY — {Math.round(config.overlayOpacity * 100)}%
            </div>
            <input
              type="range" min={0} max={100}
              value={Math.round(config.overlayOpacity * 100)}
              onChange={e => onChange({ ...config, overlayOpacity: Number(e.target.value) / 100 })}
              style={{ width: "100%", accentColor: C.brand[400], cursor: "pointer" }}
            />
            <div style={{ display: "flex", justifyContent: "space-between", fontFamily: T.typography.label.family, fontSize: "9px", color: C.green[600] }}>
              <span>Image only</span><span>Solid color</span>
            </div>
          </div>

          {/* Overlay color */}
          <div>
            <div style={{ fontFamily: T.typography.label.family, fontSize: "10px", color: C.green[400], letterSpacing: "0.1em", marginBottom: "8px" }}>
              OVERLAY TINT
            </div>
            <div style={{ display: "flex", gap: "6px" }}>
              {[
                { hex: C.green[900], label: "Forest" },
                { hex: "#000000",    label: "Black" },
                { hex: C.brand[900], label: "Amber" },
              ].map(({ hex, label }) => (
                <div
                  key={hex}
                  onClick={() => onChange({ ...config, overlayColor: hex })}
                  title={label}
                  style={{
                    width: "32px", height: "32px", background: hex, cursor: "pointer",
                    border: config.overlayColor === hex ? `2px solid ${C.brand[400]}` : "2px solid transparent",
                    transition: "border-color 150ms",
                  }}
                />
              ))}
            </div>
          </div>

          {/* Position */}
          <div>
            <div style={{ fontFamily: T.typography.label.family, fontSize: "10px", color: C.green[400], letterSpacing: "0.1em", marginBottom: "8px" }}>
              FOCAL POINT
            </div>
            <div style={{ display: "flex", gap: "4px", flexWrap: "wrap", maxWidth: "100px" }}>
              {["top left","top center","top right","center left","center","center right","bottom left","bottom center","bottom right"].map(pos => (
                <div
                  key={pos}
                  onClick={() => onChange({ ...config, bgPosition: pos })}
                  title={pos}
                  style={{
                    width: "28px", height: "20px", cursor: "pointer",
                    background: config.bgPosition === pos ? C.brand[400] : C.green[700],
                    border: `1px solid ${config.bgPosition === pos ? C.brand[600] : C.green[600]}`,
                    transition: "all 150ms",
                  }}
                />
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

